#define BUFFER_SIZE 1024

void replaceWord(const char* search, const char* replace, char* subject) {
    char buffer[BUFFER_SIZE];
    char* insert_point = &buffer[0];
    const char* temp = subject;

    size_t search_len = strlen(search);
    size_t replace_len = strlen(replace);

    while (1) {
        const char* p = strstr(temp, search);

        // If string not found, copy the rest of the string
        if (p == NULL) {
            strcpy(insert_point, temp);
            break;
        }

        // Copy part before the found string
        memcpy(insert_point, temp, p - temp);
        insert_point += p - temp;

        // Copy replacement string
        memcpy(insert_point, replace, replace_len);
        insert_point += replace_len;

        // Adjust temp pointer
        temp = p + search_len;
    }

    // Finish by writing what's in the buffer back to the subject
    strcpy(subject, buffer);
}

